#include <bits/stdc++.h>
using namespace std;
int sum[10]={6,2,5,5,4,5,6,3,7,6};
int main(){
	//freopen("sticks.in","r",stdin);
	//freopen("sticks.out","w",stdout);
	int t,n;
	scanf("%d",&t);
	while(t--){
		scanf("%d",&n);
		if(n==1){
			printf("-1\n");
		}else if(n%7==0){
			for(int i=1;i<=n/7;i++)
				printf("8");
			printf("\n");
		}else if(n%7==1){
			printf("10");
			n-=8;
			for(int i=1;i<=n/7;i++)
				printf("8");
			printf("\n");
		}else{
			int tmp=n,m=n/7+(n%7>0);
			for(int i=1;i<=m;i++){
				for(int j=(i==1);j<10;j++)
					if(tmp-sum[j]<=(m-i)*7 && tmp>=sum[j]){
						tmp-=sum[j];
						printf("%d",j);
						break;
					}
			}
			printf("\n");
		}
	}
	return 0;
}
